// Validar auth + payload en un solo nodo.
// Auth: header X-FTS-Session-Token (base64(JSON(session)))
// El frontend de config-master-master lo arma así:
//   btoa(unescape(encodeURIComponent(JSON.stringify({userId, username, role, loginTime, ts}))))

const req = $input.first().json;
const headers = (req && req.headers) || {};
const token = headers['x-fts-session-token'] || headers['X-FTS-Session-Token'] || '';

if (!token){
  return [{ json: {
    _error: true,
    codigo: 'AUTH_MISSING',
    mensaje: 'Falta el header X-FTS-Session-Token'
  }}];
}

let session = null;
try {
  const decoded = Buffer.from(token, 'base64').toString('utf8');
  session = JSON.parse(decoded);
} catch(e){
  return [{ json: {
    _error: true,
    codigo: 'AUTH_BAD_TOKEN',
    mensaje: 'Token inválido o mal formado'
  }}];
}

if (!session || session.role !== 'master'){
  return [{ json: {
    _error: true,
    codigo: 'AUTH_FAILED',
    mensaje: 'Solo master puede modificar accesos'
  }}];
}

// Validar payload
const body = req.body || {};
const accesos = body.accesos || null;

if (!accesos || typeof accesos !== 'object'){
  return [{ json: {
    _error: true,
    codigo: 'INVALID_PAYLOAD',
    mensaje: 'Falta el objeto "accesos"'
  }}];
}

const sups = accesos.supervisores_por_depto;
if (!sups || typeof sups !== 'object' || Array.isArray(sups)){
  return [{ json: {
    _error: true,
    codigo: 'INVALID_PAYLOAD',
    mensaje: '"supervisores_por_depto" debe ser un objeto'
  }}];
}

const rh = accesos.rh;
if (!Array.isArray(rh)){
  return [{ json: {
    _error: true,
    codigo: 'INVALID_PAYLOAD',
    mensaje: '"rh" debe ser un array de empleado_ids'
  }}];
}

// Validar contenido de sups: cada key debe ser stringified int, cada value debe ser array de ints
for (const deptId of Object.keys(sups)){
  if (!/^[0-9]+$/.test(String(deptId))){
    return [{ json: {
      _error: true,
      codigo: 'INVALID_PAYLOAD',
      mensaje: 'Departamento inválido en supervisores_por_depto: ' + deptId
    }}];
  }
  if (!Array.isArray(sups[deptId])){
    return [{ json: {
      _error: true,
      codigo: 'INVALID_PAYLOAD',
      mensaje: 'Valor de depto ' + deptId + ' debe ser array'
    }}];
  }
  for (const empId of sups[deptId]){
    if (!Number.isInteger(empId)){
      return [{ json: {
        _error: true,
        codigo: 'INVALID_PAYLOAD',
        mensaje: 'empleado_id inválido en depto ' + deptId + ': ' + empId
      }}];
    }
  }
}

for (const empId of rh){
  if (!Number.isInteger(empId)){
    return [{ json: {
      _error: true,
      codigo: 'INVALID_PAYLOAD',
      mensaje: 'empleado_id inválido en rh: ' + empId
    }}];
  }
}

// Normalizar + construir objeto final
const nuevo = {
  version: 1,
  supervisores_por_depto: sups,
  rh: rh,
  updated_at: new Date().toISOString(),
  updated_by: session.username || ('userId:' + session.userId)
};

return [{ json: { nuevo_accesos: nuevo, session_username: session.username } }];

// Reemplaza el archivo completo con el nuevo contenido validado.
// Preserva el SHA si existía (para update), o lo omite si era primer write (404 tolerado).
const ghResp = $input.first().json;
const prev   = $('Code - Validar auth + payload').item.json;
const nuevo  = prev.nuevo_accesos;

let sha = null;
if (ghResp && ghResp.sha){
  sha = ghResp.sha;
}

const nuevoStr = JSON.stringify(nuevo, null, 2);
const nuevoB64 = Buffer.from(nuevoStr, 'utf8').toString('base64');

return [{
  json: {
    sha: sha || '',
    content: nuevoB64,
    message: 'accesos-panel-incidencias: actualizado por ' + (prev.session_username || 'master'),
    nuevo_accesos: nuevo
  }
}];

const prev = $('Code - Merge').item.json;
return [{
  json: {
    success: true,
    accesos: prev.nuevo_accesos,
    mensaje: 'Accesos actualizados'
  }
}];
